  const { t } = useTranslation('actionPagesBuilder');
  if (productsForRecurringOnly) {
    if (minimumGiftAmount) {
      return (
        <Wrapper>
          <Trans
            components={[
              <b key="recurring-minimum-amount-1" />,
              <b key="recurring-minimum-amount-2" />,
            ]}
            i18nKey="goaaAlert.recurringWithMinimum"
            t={t}
            values={{
              minimumAmount: formatCurrency(minimumGiftAmount),
            }}
          />
        </Wrapper>
      );
    }

    return (
      <Wrapper>
        <Trans
          components={[<b key="recurring-amount-1" />, <b key="recurring-amount-2" />]}
          i18nKey="goaaAlert.recurring"
          t={t}
        />
      </Wrapper>
    );
  }

  if (minimumGiftAmount) {
    return (
      <Wrapper>
        <Trans
          components={[<b key="minimum-amount-1" />, <b key="minimum-amount-2" />]}
          i18nKey="goaaAlert.minimum"
          t={t}
          values={{
            minimumAmount: formatCurrency(minimumGiftAmount),
          }}
        />
      </Wrapper>
    );
  }

  return null;
};

