import { ActionPageFinancePreset, AmountAllocation } from '@domain/actionPages';
import { useTotalAmount } from '@pages/ActionPages/pages/PublicActionPage/ActionPageView/ActionPageLayout/ActionPageBody/hooks';
import { tw } from '@utils/useTailwind';
import { clsx } from 'clsx';
import currency from 'currency.js';
import DOMPurify from 'dompurify';
import { useCallback, useMemo } from 'react';
import { useFormContext } from 'react-hook-form';
import { Trans, useTranslation } from 'react-i18next';
import { Button } from '../../../Button';
import { useBoolean } from '../../../FormControl/hooks';
import { DeleteIcon } from '../../../icons';
import { Label } from '../../../Label';
import { AddItemPopover } from '../../../Popover/AddItemPopover';
import { FundAmountInput, FundSelection } from './FundAmountInput';

type Props = {
  addFund?: (fundId: string) => void;
  additionalFunds: FundSelection[];
  allowModificationsOfFunds: boolean;
  amountAllocations?: AmountAllocation[];
  amounts?: ActionPageFinancePreset[];
  className?: string;
  funds: FundSelection[];
  multiFundExpanded?: boolean;
  primaryAccountId?: string;
  removeFund?: (fundId: string, amountAllocations: AmountAllocation[]) => void;
  setAllocationAmount?: (val: AmountAllocation[]) => void;
  setOtherAmount: (val: string | undefined, balanceAmountAllocations?: boolean) => void;
  setShowOtherInput: (val: boolean) => void;
};

export const FundsAndAmountsContainer = ({
  addFund,
  additionalFunds,
  allowModificationsOfFunds,
  amountAllocations = [],
  amounts,
  className,
  funds,
  multiFundExpanded,
  primaryAccountId,
  removeFund,
  setAllocationAmount,
  setOtherAmount,
  setShowOtherInput,
}: Props) => {
  const donationAmount = useTotalAmount();
  const { setValue } = useFormContext();
  const { t } = useTranslation(['actionPagesBuilder', 'common']);
  const [expanded, { toggle }] = useBoolean(multiFundExpanded);
  const fundsToShow = useMemo(
    () => funds.filter((x) => allowModificationsOfFunds || (x.percentage ?? 0) > 0),
    [allowModificationsOfFunds, funds]
  );

  // Only show funds in summary if they will actually have money going to them
  const fundsToShowInSummary = useMemo(
    () =>
      // If any amount has been selected and the allocations set, use allocations to determine which funds are being contributed to
      // Otherwise, use config percentages to anticipate which funds will be in play until an amount is selected
      amountAllocations.some((aa) => aa.amount > 0)
        ? funds.filter(
            (x) => (amountAllocations.find((aa) => aa.actionPagesFundId === x.id)?.amount ?? 0) > 0
          )
        : funds.filter((x) => (x.percentage ?? 0) > 0),
    [funds, amountAllocations]
  );

  const externalFundsByAccountName = useMemo(
    () =>
      [...funds, ...additionalFunds].reduce(
        (map, fund) => {
          if (fund.accountConnectionFunds?.length && fund.accountName) {
            if (!map[fund.accountName]) {
              map[fund.accountName] = [fund];
            } else {
              map[fund.accountName].push(fund);
            }
          }

          return map;
        },
        {} as Record<string, FundSelection[]>
      ),
    [additionalFunds, funds]
  );

  const internalFunds = useMemo(
    () =>
      [...funds, ...additionalFunds].filter(
        (fund) => !fund.accountConnectionFunds?.find((c) => c.accountId === primaryAccountId)
      ),
    [funds, primaryAccountId, additionalFunds]
  );

  const externalFunds = useMemo(
    () =>
      [...funds, ...additionalFunds].filter((fund) =>
        fund.accountConnectionFunds?.find((c) => c.accountId === primaryAccountId)
      ),
    [funds, primaryAccountId, additionalFunds]
  );

  const fundName = useCallback(
    (fund: FundSelection) => {
      if (!fund) {
        return '';
      }

      const isExternalFund = !!fund.accountConnectionFunds?.find(
        (c) => c.accountId === primaryAccountId
      );
      const externalFundName = fund.accountName ? `${fund.accountName} - ${fund.name}` : fund.name;

      if (externalFunds.length === 0) {
        return fund.name;
      } else if (
        (internalFunds.length < 2 && externalFunds.length === 1) ||
        (isExternalFund &&
          fund.accountName &&
          (externalFundsByAccountName[fund.accountName] || []).length < 2)
      ) {
        return isExternalFund ? externalFundName : fund.name;
      }

      return isExternalFund ? externalFundName : fund.name;
    },
    [externalFunds.length, externalFundsByAccountName, internalFunds.length, primaryAccountId]
  );

  const additionalFundsWithNames = useMemo(
    () => additionalFunds?.map((fund) => ({ ...fund, name: fundName(fund) })),
    [additionalFunds, fundName]
  );

  const onAddItem = useCallback(
    (fundSelection: FundSelection) => {
      // @ts-ignore
      addFund?.(fundSelection.fund?.id || fundSelection.id);
    },
    [addFund]
  );

  const fundAmounts = useMemo(() => {
    return amountAllocations.reduce(
      (acc, x) => ({
        ...acc,
        [x.actionPagesFundId]: x.amount || 0,
      }),
      {} as Record<string, number>
    );
  }, [amountAllocations]);

  const onChangeFundAmount = useCallback(
    (fund: FundSelection, amount: number) => {
      const newAmountAllocations = fundsToShow.map((x) => {
        const amountAllocation = amountAllocations.find((y) => y.actionPagesFundId === x.id);

        if (amountAllocation) {
          if (x.id === fund.id) {
            return {
              ...amountAllocation,
              amount,
            };
          }

          return {
            ...amountAllocation,
            amount: amountAllocation.amount,
          };
        }

        return {
          actionPagesFundId: x.id,
          amount: x.id === fund.id ? amount : 0,
          fundType: fund.type,
        };
      });

      const otherAmount = newAmountAllocations.reduce((a, b) => a + b.amount, 0) / 100;

      if (otherAmount !== 0) {
        const presetAmount = (amounts ?? []).find(
          (x) => currency(`${x.amount}`).intValue === otherAmount * 100
        );
        setShowOtherInput(!presetAmount);
        setOtherAmount(
          (newAmountAllocations.reduce((a, b) => a + b.amount, 0) / 100).toString(),
          false
        );
        setAllocationAmount?.(newAmountAllocations);
      }
    },
    [
      amountAllocations,
      amounts,
      fundsToShow,
      setAllocationAmount,
      setOtherAmount,
      setShowOtherInput,
    ]
  );

  const handleDeleteFund = useCallback(
    (fund) => {
      const newFunds = funds.filter((x) => x.id !== fund.id);
      const newAmountAllocations = newFunds.map((x) => ({
        actionPagesFundId: x.id,
        amount: Math.round(((donationAmount / newFunds.length) * 100) / 100),
        fundType: x.type,
      }));

      setValue('amountAllocationsAttributes', newAmountAllocations);

      const otherAmount = newAmountAllocations.reduce((a, b) => a + b.amount, 0) / 100;
      const presetAmount = (amounts ?? []).find(
        (x) => currency(`${x.amount}`).intValue === otherAmount * 100
      );

      if (!presetAmount) {
        setOtherAmount(otherAmount.toString(), false);
        setShowOtherInput(true);
      }

      removeFund?.(fund.id, newAmountAllocations);
    },
    [amounts, donationAmount, funds, removeFund, setOtherAmount, setShowOtherInput, setValue]
  );

  const containerClasses = clsx(
    'relative flex flex-col rounded-md bg-neutral-200 p-4',
    className && className
  );

  // Don't display Funds and Amounts unless a Donation Amount is selected/entered
  // (don't display it if only tickets are selected)
  if (donationAmount === 0) {
    return null;
  }

  return (
    <div className={containerClasses}>
      <div className="flex items-center justify-between">
        {expanded ? (
          <Label variant="bold">{t('actionPagesBuilder:designer.finance.fundsAndAmounts')}</Label>
        ) : (
          <Label variant="regular">
            <Trans
              components={[<strong key="funds-summary-strong" />]}
              count={Math.max(0, fundsToShowInSummary.length - 2)}
              i18nKey={
                fundsToShowInSummary.length === 2
                  ? 'actionPagesBuilder:designer.finance.fundsSummarySplit'
                  : 'actionPagesBuilder:designer.finance.fundsSummary'
              }
              t={t}
              values={{
                firstFund: DOMPurify.sanitize(fundName(fundsToShowInSummary[0])),
                secondFund: DOMPurify.sanitize(fundName(fundsToShowInSummary[1])),
              }}
            />
          </Label>
        )}
        {/* No point in expanding if there is only one fund and thus all the money is going to that fund */}
        {(funds.length > 1 || additionalFunds.length > 0) && (
          <Button className="ml-10" onClick={toggle} variant="link">
            {t(`common:button.${expanded ? 'hide' : 'show'}`)}
          </Button>
        )}
      </div>
      {expanded && fundsToShow.length > 0 && (
        <div className="flex flex-col pt-4">
          {fundsToShow.map((fund) => (
            <div
              className={tw`flex h-[50px] w-full items-center overflow-hidden rounded-md border border-neutral-400 bg-neutral-0
              [&:not(first-of-type)]:mt-2`}
              key={fund.id}
            >
              <div
                className={tw`ml-3 flex h-full min-w-0 grow items-center border-r-[1px] border-neutral-400 pr-4`}
              >
                <Label
                  className="overflow-hidden text-ellipsis whitespace-nowrap"
                  title={fundName(fund)}
                  variant="regular"
                >
                  {fundName(fund)}
                </Label>
              </div>
              <div
                className={clsx(
                  tw`flex h-full w-[110px] min-w-[110px] shrink-0 border-neutral-400`,
                  allowModificationsOfFunds && fundsToShow.length > 1 && 'border-r-[1px]'
                )}
              >
                <FundAmountInput
                  isDisabled={!allowModificationsOfFunds}
                  name={fund.name}
                  onChange={(value) => onChangeFundAmount(fund, value)}
                  value={fundAmounts[fund.id]}
                />
              </div>
              {allowModificationsOfFunds && fundsToShow.length > 1 ? (
                <div
                  className={tw`ml-0.5 mr-0.5 flex h-full w-[48px] min-w-[48px] shrink-0 items-center justify-center`}
                >
                  <Button
                    aria-label={t('actionPagesBuilder:fundsPanel.removeFund')}
                    className="!min-w-[2.5rem] hover:!bg-blue-100 hover:!text-neutral-600"
                    icon={<DeleteIcon className="w-[16px]" />}
                    onClick={() => handleDeleteFund(fund)}
                    size="md"
                    variant="icon"
                  />
                </div>
              ) : null}
            </div>
          ))}
        </div>
      )}
      {expanded && additionalFunds.length > 0 && (
        <AddItemPopover
          buttonText={t('actionPagesBuilder:fundsPanel.addFund')}
          closeOnSelect
          items={additionalFundsWithNames}
          onAddItem={onAddItem}
        />
      )}
    </div>
  );
};

